+    /// Generate an array of uniform random floats in `[0.0, 1.0)`.
+    ///
+    /// Mimics `rng.random(size)`.
+    #[must_use]
+    pub fn random(&mut self, size: usize) -> Vec<f64> {
+        (0..size).map(|_| self.next_f64()).collect()
+    }
