+    /// for small lambda, Knuth's algorithm for moderate lambda.
+    ///
+    /// Mimics `rng.poisson(lam, size)`.
+    #[must_use]
+    pub fn poisson(&mut self, lam: f64, size: usize) -> Vec<u64> {
+        (0..size).map(|_| {
